/// Impl-targeted harness for `move_tokens`. Kani's automatic
/// overflow / underflow / UB checks run on every path through the
/// real handler. `#[kani::unwind(34)]` bounds Pinocchio's 32-byte
/// pubkey/account comparisons plus generated valid-path loops.
/// Proof profile notes:
/// - source account order: source, destination, authority, mint, token_program
/// - ABI/dispatcher tag: 1
/// - PDA derivations: none inferred
/// - token owner/mint projections: source mint=mint owner=authority owner_pda=missing; destination mint=mint owner=authority owner_pda=missing
#[kani::proof]
#[kani::unwind(34)]
fn verify_move_tokens_impl() {
    let program_id: [u8; 32] = [42u8; 32];
    let authority_key: [u8; 32] = [7u8; 32];
    let amount: u64 = kani::any(); // spec type: U64
    kani::assume(amount > 0);
    kani::assume((amount as u64) <= u64::MAX as u64);

    let mut source = build_token_account([1u8; 32], true, false, [4u8; 32], authority_key, (amount as u64));
    let mut destination = build_token_account([2u8; 32], true, false, [4u8; 32], authority_key, (0 as u64));
    let mut authority = build_minimal_account(authority_key, true, false);
    let mut mint = build_mint_account([4u8; 32], false, false, 6u8);
    let mut token_program = build_minimal_account(SPL_TOKEN_PROGRAM_ID, false, false);

    let accounts: [ManuallyDrop<AccountInfo>; 5] = unsafe {
        [
            ManuallyDrop::new(account_info_from_stack(&mut source)),
            ManuallyDrop::new(account_info_from_stack(&mut destination)),
            ManuallyDrop::new(account_info_from_stack(&mut authority)),
            ManuallyDrop::new(account_info_from_stack(&mut mint)),
            ManuallyDrop::new(account_info_from_stack(&mut token_program)),
        ]
    };
    let accounts_slice: &[AccountInfo] = unsafe {
        core::slice::from_raw_parts(&accounts as *const _ as *const AccountInfo, 5)
    };

    let instruction_tag: u8 = 1u8;
    let mut instruction_data = [0u8; 9];
    instruction_data[0] = instruction_tag;
    let generated_instruction_data_1_bytes = (amount as u64).to_le_bytes();
    instruction_data[1] = generated_instruction_data_1_bytes[0];
    instruction_data[2] = generated_instruction_data_1_bytes[1];
    instruction_data[3] = generated_instruction_data_1_bytes[2];
    instruction_data[4] = generated_instruction_data_1_bytes[3];
    instruction_data[5] = generated_instruction_data_1_bytes[4];
    instruction_data[6] = generated_instruction_data_1_bytes[5];
    instruction_data[7] = generated_instruction_data_1_bytes[6];
    instruction_data[8] = generated_instruction_data_1_bytes[7];

    // Pre-token snapshots for generated Token.transfer assertions.
    let pre_transfer_0_from = read_token_amount(&source);
    let pre_transfer_0_to = read_token_amount(&destination);
    kani::assume(pre_transfer_0_from >= (amount as u64));
    kani::assume(pre_transfer_0_to <= u64::MAX - (amount as u64));

    // Call the user's real dispatcher. Kani's automatic checks
    // (overflow / underflow / pointer UB) verify this path.
    let _result = crate::process_instruction(&program_id, accounts_slice, &instruction_data);
    kani::cover!(_result.is_ok(), "impl success path reachable under generated profile");
    assert!(_result.is_ok(), "generated valid ABI/profile witness should reach success");

    if _result.is_ok() {
        assert_eq!(read_token_amount(&source), pre_transfer_0_from - (amount as u64));
        assert_eq!(read_token_amount(&destination), pre_transfer_0_to + (amount as u64));
    }

    // Spec ensures (reference). Kani's automatic checks cover
    // arithmetic UB; add explicit assertions below for cross-field
    // invariants (read post-state via read_token_amount(&<acct>)).
    //   ensures amount > 0
}

